function selectionSort(arr){
    for(let i = 0; i < arr.length - 1; i++){
        let minIndex = i
        for(let j = i + 1; j < arr.length; j++){
            if(arr[j] < arr[minIndex]){
                minIndex = j
            }
        }
        if(minIndex !== i){
            const tmp = arr[i]
            arr[i] = arr[minIndex]
            arr[minIndex] = tmp
        }
    }
    return arr
}

function insertionSort(arr){
    for(let i = 1; i < arr.length; i++){
        const current = arr[i]
        let j = i - 1
        while(j >= 0 && arr[j] > current){
            arr[j + 1] = arr[j]
            j--
        }
        arr[j + 1] = current
    }
    return arr
}
